var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"하아, 이 등굣길도 오늘이 마지막이네......","JPN":"はぁ、この通学路も今日で最後だな……","ENG":"*Sigh* Today is our last day at school.","TWN":"唉，這條上學的路途今天是最後一次走了……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"왜? 섭섭하기라도 해?","JPN":"どうしたの？　名残惜しい？","ENG":"Why? Are you sad?","TWN":"怎麼了？難道覺得遺憾嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그야 당연하지, 반장!","JPN":"そりゃ当然だろ、委員長！","ENG":"Of course, Class President.","TWN":"當然啦，班長！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"봄이 왔다고 꽃이 피는 땅은 이제 여기밖에 안 남았다며.","JPN":"春になって花が咲く土地は、もうここしか残ってないんだろ？","ENG":"This is the only place on Earth that still flowers in spring.","TWN":"到了春天仍會開花的土地就只剩下這裡了。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"다른 생존지구들은 그나마 멀쩡한 곳도 위상 방벽 없인 숨쉬기도 위험하다던데......","JPN":"他の生存地区だって位相防壁がないと呼吸することすら危険らしいし……","ENG":"Other surviving sectors, even the most intact ones, are so contaminated that the people have to stay inside the phase barrier just to breathe.","TWN":"聽說其它倖存地區就算完好無損，也沒有地界屏障，在那裡連呼吸都很危險……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"반장도 아쉽지 않아?","JPN":"委員長は名残惜しくないのか？","ENG":"Class President, aren't you sad?","TWN":"班長不覺得遺憾嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"매년 봄 소풍 전날만 되면 들떠서 잠도 못 자고 그랬던 것 같은데.","JPN":"毎年春の遠足の前日になると、楽しみで眠れなかったと思うけど。","ENG":"You were so excited to go on the spring picnic every year that you'd barely sleep the night before.","TWN":"我記得班長好像以往到了每年春天的遠足，前一晚都會興奮到睡不著覺的說。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그야 당연히 아쉽지.","JPN":"もちろん名残惜しいよ。","ENG":"Of course, I'm sad.","TWN":"當然遺憾啦。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아쉽긴 하지만......","JPN":"名残惜しいけど……","ENG":"I am, and...","TWN":"雖然遺憾……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그래도 괜찮아. 우리가 떠난다고 아카데미가 완전히 없어지는 건 아니잖아?","JPN":"でも大丈夫。私たちがここを去っても、アカデミーが完全になくなるわけじゃないでしょう？","ENG":"I'm not. We may be leaving, but the Academy will still be here, right?","TWN":"但沒關係。就算我們離開了，學校也不會不見啊？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"졸업도 못 하고 전선으로 떠난 친구와 선생님들도 많은데, 우린 여기 남아서 학교 생활을 조금이라도 더 누리고 있는 거니까......","JPN":"卒業もできずに戦線に行った友達や先生も多い中で、\\n私たちはここで学校生活を楽しんでいるんだから……","ENG":"Many of our friends and teachers had to go out to fight before they could graduate, and we got to enjoy more days at school.","TWN":"有許多朋友和老師都沒有畢業就去了前線，我們卻能留在這兒，稍微多享受一會兒校園生活，所以……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그것만으로도 난 감사한 마음이야.","JPN":"それだけでも私は感謝してる。","ENG":"I'm grateful just for that alone.","TWN":"光是擁有現在這樣…我已經滿懷感激了。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"난 전선에 가는 것도 상관없어.","JPN":"俺は別に戦線に行ったって構わない。","ENG":"I don't mind going out to fight.","TWN":"雖然說…讓我上前線也無所謂。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"하지만 여길 떠나면......","JPN":"でもここを離れたら……","ENG":"It's just that... if I leave this place...","TWN":"但是一旦離開了這裡…"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아직 학교에 남아 있는 녀석들이랑은 언제 다시 보게 될지 모르니까.","JPN":"学校に残っているやつらといつまた会えるかわからないから。","ENG":"I might not be able to see the others in school anymore.","TWN":"我們和那些留在學校裡的同學們…也不知道什麼時候才能再見面…"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"조금 더 같이 지내는 것도 나쁘진 않은 것 같아.","JPN":"もう少し長く一緒にいるのも悪くないと思う。","ENG":"That's why I'd love to stay with them for a little longer.","TWN":"能和他們再多相處一段時光也很不錯啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"......그런데 지금 들고 있는 거, 카메라 아냐?","JPN":"……ところで、今持ってるそれってカメラだろ？","ENG":"By the way, is that a camera in your hand?","TWN":"……呃，妳現在拿著的是攝影機嗎?"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어? 설마 그걸로 지금 나 찍고 있었어? 그런 거 아니지?","JPN":"え？　まさかそれで俺を撮ってたのか？　違うよな？","ENG":"Eh? Have you been filming me? Really?","TWN":"咦？？難道妳一直用攝影機在拍我嗎？不會吧？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"몰랐어? 기숙사 나올 때부터 계속 찍고 있었는데?","JPN":"気付かなかった？　寮を出た時からずっと撮ってたのに？","ENG":"Didn't you know? I've been filming you since we left the dorm.","TWN":"咦？？妳不知道？從宿舍出來後，我就一直在拍呀。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"기억 안 나? 어제 교장선생님이 통신문 보냈잖아.","JPN":"覚えてないの？　昨日校長先生がお便りを送ってきたでしょう？","ENG":"Don't you remember the message we got from the Principal yesterday?","TWN":"妳不記得了？昨天我們校長不是發了一則通知嘛？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"<color=#ffd34c>우리가 이 교정으로 등교하는 건 오늘이 마지막이니까, 영상으로 최대한 많은 기록을 남겨둡시다!</color> 하고 말이야.","JPN":"<color=#ffd34c>私たちがこの校舎に登校するのは今日が最後なので、できるだけ多くの映像記録を残しましょう！</color>　ってね。","ENG":"He said, <color=#ffd34c>since tomorrow will be your last day at school, try to capture as many things on video as you can</color>.","TWN":"通知：<color=#ffd34c>今日是本校學生在此學習的最後一日，請諸位學員利用影像等形式，多多記錄校園生活!</color>"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"윽, 그럼 내가 방금 부끄러운 소리한 것도 다 찍혔단 거잖아?!","JPN":"うっ、じゃあさっき俺が言った恥ずかしい話も全部撮られたってことか！？","ENG":"Ack, then were you filming me when I said those embarrassing things earlier?","TWN":"啊啊啊…那我剛才那些傻話是不是都被拍下來了！？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"바, 반장. 방금 그거 좀 편집해 주라. 방송부 부장 됐으면 그 정도는 할 수 있잖아.","JPN":"い、委員長。さっきのあれは編集してくれよ。放送部の部長ならそのくらいできるだろ。","ENG":"C-Class President, could you get rid of that part? You're the president of the broadcasting club. You can do it, right?","TWN":"班…班長呀，那個…拜託把剛才那段剪了吧。傳播部部長的話，這點事應該辦得到吧？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"부끄럽다니~ 학교친구들과 헤어지기 싫은 마음은 모두가 같은걸?","JPN":"恥ずかしいことないよ～学校の友達と離れたくない気持ちはみんな同じだから。","ENG":"Don't be embarrassed. Nobody wants to leave their friends, either.","TWN":"怎麼會丟臉？不想和同學們分離的心情，大家都是一樣~不是嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"카메라를 의식하지 않은 진심 어린 대사! 아주 좋았어!","JPN":"それに、カメラを意識しない本心からのセリフ！　すごくよかった！","ENG":"I'm glad I was able to capture your true feelings on camera.","TWN":"剛才妳沒發現到我在拍攝，那些發自內心的感言真的很棒喔！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그, 그런가......? 그렇게 좋다면야......","JPN":"そ、そうか……？　そんなによかったなら……","ENG":"D-do you think so? Well, if you say so...","TWN":"啊...這樣嗎？既然妳這樣說，那就..."},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아냐, 역시 쪽팔려! 얼른 그거 내놔!","JPN":"いや、やっぱりダメだ！　早くそれよこせ！","ENG":"No, it's still embarrassing! Give me the camera!","TWN":"不對，還是太丟臉了！快把這段刪掉啦。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"후후, 뺏어가도 어차피 못 지울걸.","JPN":"ふふ、持ってったってどうせ消せないよ。","ENG":"Hah hah. You can take the camera, but you can't erase the recording.","TWN":"嘿嘿，就算妳把攝影機搶走也刪不掉喔！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"카메라 사용법이라면 이 학교에서 나만큼 익숙한 사람도 없다고.","JPN":"カメラの使い方なら、この学校で私が一番上手だからね。","ENG":"No one else in school is as good at using that camera as I am.","TWN":"以攝影來說,這所學校裡沒有人比我更厲害了！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"......교장선생님만큼은 아니겠지만.","JPN":"……校長先生ほどじゃないけど。","ENG":"Well, except for the Principal.","TWN":"…雖然比不上校長就是了。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어, 그러고 보니 반장한테 카메라랑 방송장비 쓰는 법을 가르쳐준 사람도 교장선생님이었지?","JPN":"あ、そういえば、委員長にカメラと放送設備の使い方を教えたのも校長先生だったよな？","ENG":"Ah, now that I think of it, it was the Principal who taught you how to use the camera and other broadcasting equipment, wasn't it?","TWN":"哦~~原來，教班長如何攝影與播放的人就是校長吧？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"교장선생님은 우리가 잘 모르는 신기한 도구들도 뭐든 익숙하게 다룬다니까.","JPN":"校長先生は俺たちが知らない珍しい道具も慣れた感じで扱うからな。","ENG":"The Principal knows how to use things that we don't even know what they're for.","TWN":"嗯，校長告訴我們：對於那些新奇、我們不熟悉的設備，也要知道怎麼去使用。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"꼭 딴세상에서 온 사람 같아.","JPN":"まるで別世界から来た人みたいだ。","ENG":"It's as if he's from a completely different world.","TWN":"校長就像是從另一個世界來的一樣厲害呢。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"학교에서 교장선생님이랑 비길 만한 사람이라면 역시...... 학생회장 정도?","JPN":"この学校で校長先生に肩を並べられるような人といえば、やっぱり……生徒会長くらいかな？","ENG":"If there's someone in school who's as good as he, then it'd be the Student President, wouldn't it?","TWN":"現在我們學校能和校長一樣厲害的…也就只有學生會長之類的人物了吧？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아, 아차...... 괜히 쓸데없는 소릴 해 버렸네......","JPN":"あ、しまった……余計なことを言っちゃったな……","ENG":"O-oops, I shouldn't have said that.","TWN":"啊！糟糕…好端端的，我說這些幹嘛…"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아냐, 괜찮아.","JPN":"ううん、大丈夫よ。","ENG":"No, that's alright.","TWN":"不，沒事。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"알고 있어. 나만 아니라 다들 학생회장을 걱정하고 있다는 걸.","JPN":"知ってる。生徒会長のことを心配してるのは私だけじゃないってこと。","ENG":"I know I'm not the only one who's worried about the Student President.","TWN":"我知道。大家都很掛念她。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"응, 분명...... 살아 있겠지?","JPN":"うん、きっと……生きてるよな？","ENG":"Yes. She's still got to be alive, right?","TWN":"嗯...她...應該，還活著吧？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"물론이지. 이 사고투성이 학교에서 온갖 문제를 해결해 왔잖아.","JPN":"もちろんよ。この事件だらけの学校であらゆる問題を解決してきたんだから。","ENG":"Of course. She was strong enough to take care of all kinds of problems in school.","TWN":"那當然了！就連我們這樣一堆事故發生的學校，不也是在逐漸解決各種問題嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"분명 어딘가에서 멀쩡하게 살아 있을 거라고.","JPN":"きっとどこかで元気に生きていると思う。","ENG":"She has to be alive somewhere.","TWN":"嗯，學生會長她一定還在某個地方，好好地活著呢！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"선생님들께서 조사 중이라고 하셨으니까. 곧 좋은 소식이 있을 거야.","JPN":"先生たちも調査してると言ってたしね。もうすぐいい知らせがあるはずよ。","ENG":"The teachers are looking for her. We'll hear good news soon.","TWN":"老師們說他們正在調查搜索呢！一定很快就會有好消息傳來的。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"응...... 그랬으면 좋겠다.","JPN":"うん……だといいな。","ENG":"Yes, I hope so.","TWN":"嗯…如果是這樣就太好了。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"앗, 저 녀석...... 그때 내 간식 훔쳐간 녀석이잖아!","JPN":"あっ、あいつ……俺のおやつを盗んでいったやつだな！","ENG":"Ah, that cat! It's the cat that stole my snack!","TWN":"啊，這傢夥！不就是當時偷吃了我零食的小東西嗎!"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아, 귀엽다. 오랜만에 보네, 고양이.","JPN":"あらかわいい。猫を見るのは久しぶりね。","ENG":"Ah, so cute. Long time, no see, kitty cat.","TWN":"呀,真可愛啊~~好久不見了呢，小貓貓~"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"유진아, 가서 안아 볼래? 좋은 장면이 나올 것 같은데?","JPN":"シロコ、その子を抱きしめてみない？　いいショットが撮れそう！","ENG":"Eujin, why don't you go hold him? I want to have you with him on camera.","TWN":"劉珍，妳過去抱抱它吧？拍出來一定超可愛！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐? 내가 왜 저런 간식 도둑 녀석을 안아 줘?","JPN":"はあ？　なんで俺があのおやつ泥棒を抱きしめなきゃいけないんだよ？","ENG":"What? Why would I want to hold a snack thief?","TWN":"妳說什麼呀？我為什麼要去抱那個偷我零食的傢夥啊?"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"와아, 유진아. 네 쪽으로 온다.","JPN":"わぁ、シロコ。あなたのほうに来てるよ。","ENG":"Whoa, Eujin. He's coming your way.","TWN":"哇，劉珍，牠朝妳走過去了~"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어, 어?","JPN":"あ、あれ？","ENG":"Err, err?","TWN":"咦？啊？？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"야! 너 가까이 오지 마! 더 오면 가만 안 둬!","JPN":"おい！　お前近寄るなよ！　来たらタダじゃおかないからな！","ENG":"Hey, stay away! Or you'll be sorry!","TWN":"喂! 你別過來了喔!別再靠近我了喔！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"다리에 찰싹 붙어서 비비는 걸 보니까, 네 간식 잘 먹었다고 고마워하는 거 같은데?","JPN":"足にくっついてスリスリしてるし、おやつごちそうさまって言ってるみたいよ？","ENG":"He's rubbing himself against your leg. He must be thanking you for the snack.","TWN":"它蹭著妳的腿撒嬌呢，是不是因為當時吃了妳好吃的零食，現在來表達一下感謝啊?"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"으, 으음......","JPN":"う、ううん……","ENG":"Err...","TWN":"唔… 呃...."},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"에이, 그렇게 부끄러워하지 말고.","JPN":"もう、そんなに恥ずかしがらないで。","ENG":"Come on, don't be so shy.","TWN":"哎呀，妳這麼害羞幹什麼呀！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"한 번 안아들어 봐. 이럴 때가 아니면 또 언제 해 보겠어. 안 그래?","JPN":"抱き上げてみてよ。こんな時じゃないと、いつまたできるかわからないでしょう？","ENG":"Pick him up. You might not have another chance. Come on.","TWN":"試著抱抱它嘛~今天不抱，下次再遇到也不知道是什麼時候了，不是嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아니, 뭐...... 반장이 그렇게까지 말한다면야......","JPN":"いや、まぁ……委員長がそこまで言うなら……","ENG":"Well, if you say so...","TWN":"這個，嗯…要、要是連班長都這麼說的話,那...."},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그, 그럼 아까 녹화했던 영상 지워 주기다?","JPN":"じゃ、じゃあさっき録画した映像は消してくれよ？","ENG":"Th-then, will you delete that earlier part instead?","TWN":"那，那妳要把之前錄的那段蠢影片刪掉喔?"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"흐음~ 그럼 유진이 하는 거 봐서?","JPN":"う～ん、まぁシロコ次第かな？","ENG":"Mm... Maybe, depending on what you do.","TWN":"嗯，這就要看劉珍的表現囉？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아, 알았다고. 안아 주면 되잖아. 안아 주면.","JPN":"わ、わかったよ。やればいいんだろ、やれば。","ENG":"Okay, okay! I'll hold him. Sheesh!","TWN":"好啦，我知道啦！我抱，我抱總行了吧！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"자, 됐지?","JPN":"ほら、これでいいか？","ENG":"Here. Are you satisfied now?","TWN":"呐！行了吧！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"와아......","JPN":"わぁ……","ENG":"Wow!","TWN":"哇....."},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"유진아, 여기 봐. 여기. 이건 꼭 기록으로 남겨 둬야겠어. 너무 잘 어울린다.","JPN":"シロコ、こっち見て。これは絶対に記録として残さないと。よく似合ってるよ。","ENG":"Eujin, look. We've got to keep this part. You two look so cute together.","TWN":"劉珍，看這裡！這個場景一定要拍下來，太棒了！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"자, 이쪽 보면서 좀 더 위로 안아 봐. 엄청 푹신푹신해 보여.","JPN":"ほら、こっち向いてもっと上に抱いてみて。すごくふわふわ。","ENG":"Now, look here and hold him higher. He looks so fluffy.","TWN":"好！再看這裡，再往上抱一點。這隻貓看起來好蓬鬆的樣子呢。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"이, 이렇게?","JPN":"こ、こうか？","ENG":"L-like this?","TWN":"是...是這樣嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"안는 자세가 익숙한데? 유진이 너, 역시 고양이 좋아하는 거 아냐?","JPN":"扱い慣れてるみたいね。シロコ、やっぱり猫が好きなんじゃないの？","ENG":"You look so natural, holding him like that. Eujin, you like cats, don't you?","TWN":"妳抱貓的樣子看起來很熟練啊，劉珍妳....其實是不是超喜歡貓呀？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐어...... 딱히 고양이 좋아하는 건 아니긴 한데...... 제멋대로에다 콧대 높으니까......","JPN":"まあ……別に猫が好きなわけじゃないけど……わがままで気まぐれだし……","ENG":"Weeelll... I don't exactly like them... They're selfish and haughty...","TWN":"這個嘛...確切來說，也沒有特別喜歡…只是因為貓隨心所欲又高傲優雅的樣子才..."},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"후후, 또 그렇게 얼버무린다.","JPN":"ふふ、またそうやってごまかすんだから。","ENG":"Hah hah. You don't mean that.","TWN":"呵呵呵，妳又這樣想要瞞混過去。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"얼버무리는 거 아니라니까. 진짜라고.","JPN":"ごまかしてなんかない。本当だって。","ENG":"I do. I'm serious!","TWN":"我才沒有在敷衍妳，是真的啦！"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"유진아, 물러서!","JPN":"シロコ、下がって！","ENG":"Eujin, step back!","TWN":"劉珍！站遠一點！"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"윽, 침식체잖아? 도시로 들어오기 시작했다는 게 정말이었어?","JPN":"うっ、侵食体？　都市に入り始めたってのは本当だったのか？","ENG":"Ack, C.O.! So, it's true that they started coming into cities!","TWN":"呃，那不是侵蝕體嗎？ 真的開始進到都市裡面了？"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"저번 전투 이후로 위상 방벽 몇 군데가 제대로 작동되지 않는다고 들었어. 그리로 들어온 거 아닐까?","JPN":"この前の戦闘があってから、位相防壁が何か所か正常に作動しないって聞いた。\\nそこから入ったんじゃないかな。","ENG":"I've heard in some places the phase barrier hasn't been functioning since the last battle. Maybe they sneaked in through them.","TWN":"聽說打從上次那場戰役後，上方的相位屏障有好幾處都失靈了… 它們就是從那裡進來的吧？"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"결국 여기도 곧 전쟁터가 된다는 뜻이겠지...... 다른 사람들이 걱정이네.","JPN":"結局ここも戦場になってしまうんでしょうね……他の人たちが心配。","ENG":"Soon, this place will turn into yet another battlefield. I'm worried about the others.","TWN":"結果，這裡馬上就要成為戰場了…我很擔心其他人。"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"알겠다. 너 저 녀석들 때문에 무서워서 달라붙은 거지?","JPN":"なるほど。お前、あいつらが怖くて俺にくっついたんだな？","ENG":"I get it now. You came to me because you were scared of them, didn't you?","TWN":"我知道了！妳是因為害怕那些傢夥受傷才不想離開學校的吧?"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"좋아, 잠도 설쳐서 찌뿌둥했는데 마침 잘됐어.","JPN":"まぁいい、眠れなくてだるかったからちょうどよかった。","ENG":"Okay, I was grumpy because I didn't sleep well last night.","TWN":"哼，我連覺都睡不好，真的挺難受的，乾脆早上去吧。"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아침 운동 겸해서 박살을 내 주지!","JPN":"朝の運動がてら叩き潰してやる！","ENG":"Might as well do some morning exercises to refresh myself and destroy you guys!","TWN":"當作晨間運動順便粉碎敵人！"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"어라? 잠 못 잤어?","JPN":"え？　眠れなかった？","ENG":"Huh? Why didn't you sleep well?","TWN":"哦？妳沒睡啊~？"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"역시 유진 양~ 마지막 날의 아쉬움 때문에 뒤척거리느라 밤을 지새우셨군요~","JPN":"さすがシロコさ～ん、最後なのが寂しくて寝付けずに夜を明かしたんですね～！","ENG":"Ah, I get it. You tossed and turned, thinking about the last day at school.","TWN":"果然是劉珍“女士”啊~因為是最後一天待在學校所以依依不捨，晚上翻來覆去睡不著呢~"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아, 안 그랬어! 반장! 진짜라니까! 내가 그깟 거로 서운해했을까 봐?!","JPN":"ち、違う！　委員長！　本当だって！\\n俺がそんなことで寂しがるわけないだろ！","ENG":"I-I didn't! Class President, I mean it! There's no way I tossed and turned because of something so petty!","TWN":"啊，我才沒有，班長！是真的啦！我看起來像會為了這種小事感到難過嗎？！"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"쳇, 온다! 엄호 부탁할게!","JPN":"ちぇっ、来るぞ！　援護を頼む！","ENG":"Gah, here they come! Cover me!","TWN":"啊———快來！！請求支援！"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그래, 아카데미에서 배운 대로!","JPN":"ええ、アカデミーで習ったとおりにね！","ENG":"Okay, let's just do as we've learned at the Academy!","TWN":"就像這樣，按照學院裡學的那樣!"},"stage":{"bg":"STREET_SPRING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};